import java.io.FileWriter;
import java.io.IOException;
import org.apache.commons.text.StringEscapeUtils;

public class XSSSecureCode {
    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Escape user input to prevent script injection
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling user input by escaping and outputting it to the response
        try (FileWriter fileWriter = new FileWriter("output.html")) {
            fileWriter.write("<html>");
            fileWriter.write("<head><title>XSS Secure Example</title></head>");
            fileWriter.write("<body>");
            fileWriter.write("<h1>Welcome, " + escapedUserInput + "</h1>");
            fileWriter.write("</body>");
            fileWriter.write("</html>");
        }

        System.out.println("Secure output.html generated successfully.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
